function solve(n, edges, label) {
    // Build the graph
    let graph = Array(n).fill(null).map(() => []);
    for (let [u, v] of edges) {
        graph[u].push(v);
        graph[v].push(u);
    }

    // Helper function to check if a string is palindrome
    function isPalindrome(s) {
        let l = 0, r = s.length - 1;
        while (l < r) {
            if (s[l] !== s[r]) return false;
            l++;
            r--;
        }
        return true;
    }

    let dp = Array(1 << n);
    for (let mask = 0; mask < (1 << n); mask++) {
        dp[mask] = Array(n);
        for (let i = 0; i < n; i++) {
            dp[mask][i] = Array(n).fill(null).map(() => new Set());
        }
    }

    let ans = 0;

    for (let i = 0; i < n; i++) {
        let s = label[i];
        let mask = 1 << i;
        dp[mask][i][i].add(s);
        if (isPalindrome(s)) {
            ans = Math.max(ans, s.length);
        }
    }

    for (let [u, v] of edges) {
        let mask = (1 << u) | (1 << v);
        let s1 = label[u] + label[v];
        let s2 = label[v] + label[u];
        dp[mask][u][v].add(s1);
        dp[mask][v][u].add(s2);
        if (isPalindrome(s1)) {
            ans = Math.max(ans, 2);
        }
        if (isPalindrome(s2) && !isPalindrome(s1)) {
            ans = Math.max(ans, 2);
        }
    }

    for (let mask = 0; mask < (1 << n); mask++) {
        for (let i = 0; i < n; i++) {
            if (!(mask & (1 << i))) continue;
            for (let j = 0; j < n; j++) {
                if (!(mask & (1 << j))) continue;
                for (let nw of graph[i]) {
                    if (mask & (1 << nw)) continue;
                    let new_mask = mask | (1 << nw);
                    for (let s of dp[mask][i][j]) {
                        let new_str = label[nw] + s;
                        if (isPalindrome(new_str)) {
                            ans = Math.max(ans, new_str.length);
                        }
                        dp[new_mask][nw][j].add(new_str);
                    }
                }
                for (let nw of graph[j]) {
                    if (mask & (1 << nw)) continue;
                    let new_mask = mask | (1 << nw);
                    for (let s of dp[mask][i][j]) {
                        let new_str = s + label[nw];
                        if (isPalindrome(new_str)) {
                            ans = Math.max(ans, new_str.length);
                        }
                        dp[new_mask][i][nw].add(new_str);
                    }
                }
            }
        }
    }
    return ans;
}
